"use client";

import { StarRating } from "@/components/ratings/star-rating";
import { useState, useEffect, Suspense } from "react";
import { Question } from "../types";
import { getAllQuestions } from "../lib/api";
import { Input } from "@/components/ui/input";
import Image from "next/image";
import { Button } from "@/components/ui/button";

const imagePrefix = `${process.env.NEXT_PUBLIC_IMAGE_PREFIX}`;

export default function RatingPage() {
  const [ratings, setRatings] = useState<Record<string, number>>({});
  const [questions, setQuestions] = useState<Question[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string>("");
  const isDisabled = questions.length
    ? Object.keys(ratings).length !== questions.length
    : true;
  useEffect(() => {
    setIsLoading(true);
    getAllQuestions().then((questions: Question[]) => {
      if (questions) {
        setIsLoading(false);
        setQuestions(questions);
      } else {
        setIsLoading(false);
        setError("Error al cargar las preguntas");
      }
    });
  }, []);

  const handleRatingChange = (questionId: number, newRating: number) => {
    setRatings((prevRatings) => ({
      ...prevRatings,
      [questionId]: newRating,
    }));
  };
  const handleSubmit = () => {
    console.log(ratings);
  };
  return (
    <main>
      <div className="flex w-full justify-center mb-10 md:justify-start md:max-w-[630px] md:mx-auto">
        <a href="/">
          <div className="flex">
            <Image
              alt="logo"
              src={`${imagePrefix}logo.png`}
              width={400}
              height={100}
              className="logo"
              priority
            />
          </div>
        </a>
      </div>

      <div className="contract-wizard">
        {error && <div className="flex justify-center">{error}</div>}
        {isLoading ? (
          <div className="flex justify-center">Cargando preguntas...</div>
        ) : (
          <form onSubmit={handleSubmit}>
            <h2>
              ¡Gracias por haber participado en nuestras actividades de
              voluntariado con nosotros en la Fundación Altius!
            </h2>
            <p>
              Para mejorar te pedimos por favor que llenes esta encuesta
              anónima:
            </p>
            <ol className="list-decimal ml-5">
              {questions.map((question: Question) => (
                <li key={question.id} className="mb-4">
                  <p>{question.text}</p>
                  <div className="mb">
                    <StarRating
                      value={ratings[question.id] || 0}
                      onChange={(newRating) =>
                        handleRatingChange(question.id, newRating)
                      }
                      maxRating={5}
                      size="w-6 h-6"
                    />
                  </div>
                </li>
              ))}
              <li>
                <p>¿Algo adicional que quieras añadir?</p>
                <Input placeholder="Ingresa tu respuesta..." />
              </li>
            </ol>
            <div className="flex justify-end">
              <Button disabled={isDisabled} className="mt-2">Enviar</Button>
            </div>
          </form>
        )}
      </div>
    </main>
  );
}
